import React, { useState } from 'react';
import { Copy, CheckCircle } from 'lucide-react';

const InformativeWebsite = () => {
  const [copiedIndex, setCopiedIndex] = useState(null);

  const handleCopy = (text, index) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedIndex(index);
      setTimeout(() => setCopiedIndex(null), 2000);
    });
  };

  return (
    <div className="bg-gray-900 text-white h-screen overflow-y-auto">
      <div className="max-w-4xl mx-auto space-y-8 py-12">
        {/* Intro Section */}
        <section>
          <h1 className="text-4xl font-bold mb-4">How do you know if the customer, Pleadings can be performed.</h1>
          <p className="text-lg text-gray-300">
           
          </p>
        </section>

        {/* Details Section */}
        <section>
          <h2 className="text-2xl font-bold mb-4"></h2>
          <p className="text-lg text-gray-300">
          First we have to confirm that the customer's NTA is his. This can be done by looking at the <strong>File No: </strong> 
          at the top, where the client's A# appears, if these match, we can continue.
          </p>
        </section>
      {/* Image Section */}
      <section>
          <img
            src="https://i.postimg.cc/SRvKjFx0/474264843-616102407629949-2497986332019055160-n.png"
            alt="Example of pleadings uploaded."
            className="w-full rounded-lg shadow-md"
          />
          <p className="text-sm text-gray-400 mt-2 text-center">
          </p>
        </section>

        {/* Additional Info Section */}
        <section>
          <h2 className="text-2xl font-bold mb-4">Is the respondent dated or not?</h2>
          <p className="text-lg text-gray-300">
          To find out if the respondent needs NTA or not, we have to look at the last part of the first page. If the client has  
          <strong>“a date to be set”</strong> instead of a date, PLEADINGS CANNOT BE PERFORMED, because of a defective NTA.
          </p>
          <br />
          {/* Image Section */}
      <section>
          <h2 className="text-2xl font-bold mb-4">How to identify NTA.</h2>
          <img
            src="https://i.postimg.cc/j295g0Nx/474489956-1131443084993702-5577097624803274819-n.png"
            alt="Example of pleadings uploaded."
            className="w-full rounded-lg shadow-md"
          />
          <p className="text-sm text-gray-400 mt-2 text-center">
          </p>
        </section>
        <br></br>
        <h2 className="text-2xl font-bold mb-4">How to identify i-589.</h2>
        
          <p className="text-lg text-gray-300 mt-4">
          To identify the i-589 in the client portal, it literally says <strong>"i-589”</strong>, it is valid for 2 years, so if the NTA is dated 2023, 
          we have to request for a new i-589. We can identify the I-589 as follows.
          </p>
        </section>

        {/* Image Section */}
        <section>
          <h2 className="text-2xl font-bold mb-4">How to identify NTA.</h2>
          <img
            src="/api/placeholder/800/400"
            alt="Imagen Ilustrativa"
            className="w-full rounded-lg shadow-md"
          />
          <p className="text-sm text-gray-400 mt-2 text-center">
            Descripción o pie de foto para la imagen
          </p>
        </section>
      </div>
    </div>
  );
};

export default InformativeWebsite;
